CREATE TABLE IF NOT EXISTS "SP_WarehouseZones" ("Id" SERIAL PRIMARY KEY, "TenantId" INT NOT NULL, "Name" VARCHAR(100) NOT NULL, "Code" VARCHAR(20) NOT NULL, "Type" VARCHAR(20) DEFAULT 'General', "Description" VARCHAR(500), "IsActive" BOOLEAN DEFAULT TRUE, "SortOrder" INT DEFAULT 0, "CreatedBy" VARCHAR(50) NOT NULL, "CreatedAt" TIMESTAMP DEFAULT NOW(), "UpdatedBy" VARCHAR(50), "UpdatedAt" TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SP_WarehouseLocations" ("Id" SERIAL PRIMARY KEY, "TenantId" INT NOT NULL, "WarehouseZoneId" INT NOT NULL, "Code" VARCHAR(50) NOT NULL, "Type" VARCHAR(20) DEFAULT 'Shelf', "ProductId" INT, "CurrentQuantity" INT DEFAULT 0, "MaxCapacity" INT DEFAULT 1000, "IsActive" BOOLEAN DEFAULT TRUE, "IsOccupied" BOOLEAN DEFAULT FALSE, "CreatedBy" VARCHAR(50) NOT NULL, "CreatedAt" TIMESTAMP DEFAULT NOW(), "UpdatedBy" VARCHAR(50), "UpdatedAt" TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SP_InventoryMovements" ("Id" SERIAL PRIMARY KEY, "TenantId" INT NOT NULL, "ProductId" INT NOT NULL, "VariantId" INT, "MovementType" VARCHAR(20) NOT NULL, "Quantity" INT NOT NULL, "PreviousStock" INT DEFAULT 0, "NewStock" INT DEFAULT 0, "FromLocationId" INT, "ToLocationId" INT, "OrderId" INT, "PurchaseOrderId" INT, "ReferenceNumber" VARCHAR(50), "Reason" VARCHAR(500), "CreatedBy" VARCHAR(50) NOT NULL, "CreatedAt" TIMESTAMP DEFAULT NOW(), "UpdatedBy" VARCHAR(50), "UpdatedAt" TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SP_PickingOrders" ("Id" SERIAL PRIMARY KEY, "TenantId" INT NOT NULL, "PickingNumber" VARCHAR(50) NOT NULL, "OrderId" INT NOT NULL, "Status" VARCHAR(20) DEFAULT 'Pending', "AssignedUserId" INT, "StartedAt" TIMESTAMP, "CompletedAt" TIMESTAMP, "TotalItems" INT DEFAULT 0, "PickedItems" INT DEFAULT 0, "Priority" VARCHAR(20) DEFAULT 'Normal', "Notes" VARCHAR(500), "CreatedBy" VARCHAR(50) NOT NULL, "CreatedAt" TIMESTAMP DEFAULT NOW(), "UpdatedBy" VARCHAR(50), "UpdatedAt" TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SP_PickingItems" ("Id" SERIAL PRIMARY KEY, "TenantId" INT NOT NULL, "PickingOrderId" INT NOT NULL, "ProductId" INT NOT NULL, "VariantId" INT, "LocationId" INT NOT NULL DEFAULT 0, "RequestedQuantity" INT DEFAULT 0, "PickedQuantity" INT DEFAULT 0, "Status" VARCHAR(20) DEFAULT 'Pending', "PickedAt" TIMESTAMP, "BarcodeScanned" VARCHAR(200), "CreatedBy" VARCHAR(50) NOT NULL, "CreatedAt" TIMESTAMP DEFAULT NOW(), "UpdatedBy" VARCHAR(50), "UpdatedAt" TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SP_PackingSlips" ("Id" SERIAL PRIMARY KEY, "TenantId" INT NOT NULL, "PackingNumber" VARCHAR(50) NOT NULL, "OrderId" INT NOT NULL, "PickingOrderId" INT, "Status" VARCHAR(20) DEFAULT 'Pending', "PackedByUserId" INT, "TrackingNumber" VARCHAR(50), "CarrierName" VARCHAR(50), "TotalWeight" DECIMAL(18,2) DEFAULT 0, "BoxSize" VARCHAR(50), "PackedAt" TIMESTAMP, "ShippedAt" TIMESTAMP, "Notes" VARCHAR(500), "CreatedBy" VARCHAR(50) NOT NULL, "CreatedAt" TIMESTAMP DEFAULT NOW(), "UpdatedBy" VARCHAR(50), "UpdatedAt" TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SP_BarcodeMappings" ("Id" SERIAL PRIMARY KEY, "TenantId" INT NOT NULL, "Barcode" VARCHAR(200) NOT NULL, "BarcodeType" VARCHAR(20) DEFAULT 'EAN13', "EntityType" VARCHAR(20) DEFAULT 'Product', "EntityId" INT NOT NULL, "IsActive" BOOLEAN DEFAULT TRUE, "CreatedBy" VARCHAR(50) NOT NULL, "CreatedAt" TIMESTAMP DEFAULT NOW(), "UpdatedBy" VARCHAR(50), "UpdatedAt" TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SP_CustomerSegments" ("Id" SERIAL PRIMARY KEY, "TenantId" INT NOT NULL, "Name" VARCHAR(100) NOT NULL, "Description" VARCHAR(500), "Type" VARCHAR(20) DEFAULT 'Manual', "RulesJson" JSONB, "MemberCount" INT DEFAULT 0, "IsActive" BOOLEAN DEFAULT TRUE, "LastCalculatedAt" TIMESTAMP, "CreatedBy" VARCHAR(50) NOT NULL, "CreatedAt" TIMESTAMP DEFAULT NOW(), "UpdatedBy" VARCHAR(50), "UpdatedAt" TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SP_CustomerTags" ("Id" SERIAL PRIMARY KEY, "TenantId" INT NOT NULL, "Name" VARCHAR(50) NOT NULL, "Color" VARCHAR(7) DEFAULT '#3B82F6', "Description" VARCHAR(200), "CreatedBy" VARCHAR(50) NOT NULL, "CreatedAt" TIMESTAMP DEFAULT NOW(), "UpdatedBy" VARCHAR(50), "UpdatedAt" TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SP_CustomerTagAssignments" ("Id" SERIAL PRIMARY KEY, "TenantId" INT NOT NULL, "UserId" INT NOT NULL, "CustomerTagId" INT, "CustomerSegmentId" INT, "CreatedBy" VARCHAR(50) NOT NULL, "CreatedAt" TIMESTAMP DEFAULT NOW(), "UpdatedBy" VARCHAR(50), "UpdatedAt" TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SP_CsTickets" ("Id" SERIAL PRIMARY KEY, "TenantId" INT NOT NULL, "TicketNumber" VARCHAR(50) NOT NULL, "UserId" INT NOT NULL, "OrderId" INT, "Subject" VARCHAR(200) NOT NULL, "Category" VARCHAR(20) DEFAULT 'General', "Status" VARCHAR(20) DEFAULT 'Open', "Priority" VARCHAR(20) DEFAULT 'Normal', "AssignedToUserId" INT, "FirstResponseAt" TIMESTAMP, "ResolvedAt" TIMESTAMP, "ClosedAt" TIMESTAMP, "SatisfactionRating" INT, "SatisfactionComment" VARCHAR(500), "CreatedBy" VARCHAR(50) NOT NULL, "CreatedAt" TIMESTAMP DEFAULT NOW(), "UpdatedBy" VARCHAR(50), "UpdatedAt" TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SP_CsTicketMessages" ("Id" SERIAL PRIMARY KEY, "TenantId" INT NOT NULL, "CsTicketId" INT NOT NULL, "SenderId" INT NOT NULL, "SenderType" VARCHAR(20) DEFAULT 'Customer', "Content" TEXT NOT NULL, "AttachmentUrl" VARCHAR(500), "IsInternal" BOOLEAN DEFAULT FALSE, "CreatedBy" VARCHAR(50) NOT NULL, "CreatedAt" TIMESTAMP DEFAULT NOW(), "UpdatedBy" VARCHAR(50), "UpdatedAt" TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SP_CustomerJourneyEvents" ("Id" SERIAL PRIMARY KEY, "TenantId" INT NOT NULL, "UserId" INT NOT NULL, "EventType" VARCHAR(50) NOT NULL, "EventDetail" VARCHAR(200), "ReferenceId" INT, "ReferenceType" VARCHAR(50), "MetadataJson" JSONB, "Channel" VARCHAR(50), "SessionId" VARCHAR(50), "CreatedBy" VARCHAR(50) NOT NULL, "CreatedAt" TIMESTAMP DEFAULT NOW(), "UpdatedBy" VARCHAR(50), "UpdatedAt" TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SP_ChartOfAccounts" ("Id" SERIAL PRIMARY KEY, "TenantId" INT NOT NULL, "AccountCode" VARCHAR(20) NOT NULL, "Name" VARCHAR(100) NOT NULL, "AccountType" VARCHAR(20) NOT NULL, "ParentAccountCode" VARCHAR(20), "Level" INT DEFAULT 1, "IsActive" BOOLEAN DEFAULT TRUE, "Description" VARCHAR(500), "CreatedBy" VARCHAR(50) NOT NULL, "CreatedAt" TIMESTAMP DEFAULT NOW(), "UpdatedBy" VARCHAR(50), "UpdatedAt" TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SP_AccountEntries" ("Id" SERIAL PRIMARY KEY, "TenantId" INT NOT NULL, "EntryNumber" VARCHAR(50) NOT NULL, "ChartOfAccountId" INT NOT NULL, "EntryDate" TIMESTAMP NOT NULL, "EntryType" VARCHAR(10) NOT NULL, "Amount" DECIMAL(18,2) NOT NULL, "Description" VARCHAR(500) NOT NULL, "ReferenceType" VARCHAR(50), "ReferenceId" INT, "Status" VARCHAR(20) DEFAULT 'Draft', "ApprovedByUserId" INT, "ApprovedAt" TIMESTAMP, "CreatedBy" VARCHAR(50) NOT NULL, "CreatedAt" TIMESTAMP DEFAULT NOW(), "UpdatedBy" VARCHAR(50), "UpdatedAt" TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SP_Employees" ("Id" SERIAL PRIMARY KEY, "TenantId" INT NOT NULL, "UserId" INT, "EmployeeNumber" VARCHAR(50) NOT NULL, "Name" VARCHAR(100) NOT NULL, "Email" VARCHAR(200), "Phone" VARCHAR(20), "Department" VARCHAR(50) NOT NULL, "Position" VARCHAR(50) NOT NULL, "HireDate" TIMESTAMP NOT NULL, "TerminationDate" TIMESTAMP, "Status" VARCHAR(20) DEFAULT 'Active', "BaseSalary" DECIMAL(18,0) DEFAULT 0, "PayType" VARCHAR(20) DEFAULT 'Monthly', "CreatedBy" VARCHAR(50) NOT NULL, "CreatedAt" TIMESTAMP DEFAULT NOW(), "UpdatedBy" VARCHAR(50), "UpdatedAt" TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SP_Attendances" ("Id" SERIAL PRIMARY KEY, "TenantId" INT NOT NULL, "EmployeeId" INT NOT NULL, "WorkDate" TIMESTAMP NOT NULL, "CheckInAt" TIMESTAMP, "CheckOutAt" TIMESTAMP, "Status" VARCHAR(20) DEFAULT 'Present', "LeaveType" VARCHAR(20), "WorkHours" DOUBLE PRECISION DEFAULT 0, "OvertimeHours" DOUBLE PRECISION DEFAULT 0, "Notes" VARCHAR(500), "CreatedBy" VARCHAR(50) NOT NULL, "CreatedAt" TIMESTAMP DEFAULT NOW(), "UpdatedBy" VARCHAR(50), "UpdatedAt" TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SP_Payrolls" ("Id" SERIAL PRIMARY KEY, "TenantId" INT NOT NULL, "EmployeeId" INT NOT NULL, "PayPeriod" VARCHAR(10) NOT NULL, "BasePay" DECIMAL(18,0) DEFAULT 0, "OvertimePay" DECIMAL(18,0) DEFAULT 0, "Bonus" DECIMAL(18,0) DEFAULT 0, "Deductions" DECIMAL(18,0) DEFAULT 0, "TaxAmount" DECIMAL(18,0) DEFAULT 0, "InsuranceAmount" DECIMAL(18,0) DEFAULT 0, "NetPay" DECIMAL(18,0) DEFAULT 0, "Status" VARCHAR(20) DEFAULT 'Draft', "PaidAt" TIMESTAMP, "Notes" VARCHAR(500), "CreatedBy" VARCHAR(50) NOT NULL, "CreatedAt" TIMESTAMP DEFAULT NOW(), "UpdatedBy" VARCHAR(50), "UpdatedAt" TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SP_CostAnalyses" ("Id" SERIAL PRIMARY KEY, "TenantId" INT NOT NULL, "ProductId" INT, "AnalysisPeriod" VARCHAR(10) NOT NULL, "MaterialCost" DECIMAL(18,2) DEFAULT 0, "LaborCost" DECIMAL(18,2) DEFAULT 0, "OverheadCost" DECIMAL(18,2) DEFAULT 0, "TotalCost" DECIMAL(18,2) DEFAULT 0, "Revenue" DECIMAL(18,2) DEFAULT 0, "GrossProfit" DECIMAL(18,2) DEFAULT 0, "GrossMarginPercent" DECIMAL(5,2) DEFAULT 0, "UnitsSold" INT DEFAULT 0, "CostPerUnit" DECIMAL(18,2) DEFAULT 0, "CreatedBy" VARCHAR(50) NOT NULL, "CreatedAt" TIMESTAMP DEFAULT NOW(), "UpdatedBy" VARCHAR(50), "UpdatedAt" TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SP_TenantApplications" ("Id" SERIAL PRIMARY KEY, "CompanyName" VARCHAR(100) NOT NULL, "DesiredSlug" VARCHAR(50) NOT NULL, "Email" VARCHAR(200) NOT NULL, "Phone" VARCHAR(20), "ContactName" VARCHAR(100) NOT NULL, "BusinessType" VARCHAR(20) NOT NULL, "PlanTier" VARCHAR(20) DEFAULT 'Starter', "BusinessDescription" VARCHAR(2000), "WebsiteUrl" VARCHAR(500), "NeedsMes" BOOLEAN DEFAULT FALSE, "NeedsWms" BOOLEAN DEFAULT FALSE, "NeedsErp" BOOLEAN DEFAULT FALSE, "NeedsCrm" BOOLEAN DEFAULT FALSE, "Status" VARCHAR(20) DEFAULT 'Pending', "ProvisionedTenantId" INT, "ReviewedAt" TIMESTAMP, "ApprovedAt" TIMESTAMP, "ProvisionedAt" TIMESTAMP, "RejectedAt" TIMESTAMP, "RejectionReason" VARCHAR(500), "AdminNotes" VARCHAR(500), "AdditionalInfoJson" JSONB, "CreatedBy" VARCHAR(50) NOT NULL, "CreatedAt" TIMESTAMP DEFAULT NOW(), "UpdatedBy" VARCHAR(50), "UpdatedAt" TIMESTAMP);
ALTER TABLE "SP_Users" ADD COLUMN IF NOT EXISTS "MustChangePassword" BOOLEAN DEFAULT FALSE;
